                  className="absolute inset-0 rounded-full pointer-events-none"
                  style={{
                    background: "radial-gradient(ellipse 40% 40% at 25% 25%, rgba(255,255,255,0.8), rgba(255,255,255,0.3) 15%, transparent 50%)",
                    opacity: isSelected ? 0.6 : 0.4,
